INSERT INTO "lged_children" VALUES(27,'1.02',NULL,'Project Profile Signboard: Providing and fixing of typical project profile signboard as per direction of E-I-C, to be placed at a suitable place of the site including submission of proposals for the materials & size of the signboards (recommended size: 1800mm x 1200 mm with 2 nos. 75mm dia. MS post, outer & inner frames of board shall be 50mm x 50mm x 5mm & 25mm x 25mm x 5 mm respectively ) and text layout to the engineer for approval which will be positioned as directed by the engineer and remo','sqm',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,17341.55,17293.32,17220.96,17220.96);
INSERT INTO "lged_children" VALUES(28,'1.03',NULL,'Supplying and providing of first aid box with necessary materials/medicine (hygienic gown, thermometer, adhesive dressings, antiseptic solutions, bandages, cotton balls or swaps, emergency blanket, gloves, hand sanitizer, ice pack, saline etc ). All complete as per direction of Engineer-in -charge. [PWD 01.1.4.3]','each',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,16665.42,16665.42,16665.42,16665.42);
INSERT INTO "lged_children" VALUES(29,'1.04',NULL,'Hiring, installation, testing & commissioning of CCTV/Surveillance facilities for monitoring construction site including supply, fixing of 5.0 megapixel IR fixed bullet network IP camera including lens, bracket, housing with outdoor night vision facilities, full HD 1080 pixel, real time video, network video recorder (NVR) , 2 TB HDD for NVR , 4/8/16/32 port PoE switch, 32"/42" Full HD CCTV monitor, cable & accessories, internet connection with operation & maintenance cost throughout contract com','job',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,50444.36,50444.36,50444.36,50444.36);
INSERT INTO "lged_children" VALUES(30,'1.05',NULL,'Mobilization and cleaning site before commencing actual physical work and during contract period and demobilization after completion of the works under contract to be accepted by the Engineer-in-charge. This work shall also cover cleaning and clearing, cutting or filling, dressing the project area on and in the ground to an extent that all the events of works of the project can be executed smoothly in a working environment with a particular attention on safety and security in all respects, and t','sqm',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,224.06,219.94,203.5,203.5);
INSERT INTO "lged_children" VALUES(31,'1.06',NULL,'Providing expertised architect having minimum qualification Bachelor of Architecture and relevant experience(s) more than 5 years with registration in respective professional body for detail documentation of architectural themes, drawings, working out shop drawings, communication with theme architect & getting approval, specifying architectural needs according to approved master architectural themes & plan, certifying as built drawing for the approval etc. and any relevant jobs assigned by the H','per month',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,82222.22,82222.22,82222.22,82222.22);
INSERT INTO "lged_children" VALUES(32,'1.07',NULL,'Providing expertised engineer having minimum qualification B.Sc. in Civil Engineering and relevant experience(s) more than 10 years with registration in respective professional body for project documentation, progress study & adjustment, preparation of project material schedule and testing schdule for approval etc. & jobs assigned by the HOPE or his official, at site (max man month not greater than 1/4 of initial contract duration or contract completion time whichever is less & payment for the i','per month',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,123333.33,123333.33,123333.33,123333.33);
INSERT INTO "lged_children" VALUES(33,'1.08',NULL,'Bench Mark Pillar: Manufacturing, supplying & fixing in position RCC (1:2:4) Bench Mark Pillars of size 150mm x 150mm x 750mm, with 400mm x 400mm x 100mm base having 3 nos. 10mm dia MS bar each way at base, 4 nos. 10mm dia vertical bar and 8 nos. 6mm dia tie, including cost of form works, concreting, reinforcement, plastering at top, inscribing on exposed surface, finishing surface, curing, earth cutting, embedding 450mm below GL., backfilling, ramming etc. complete as per direction of E-I-C.','each',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,1399.01,1393.53,1358.5,1358.5);
INSERT INTO "lged_children" VALUES(34,'1.09',NULL,'Providing 3 sets as-built drawings subject to Engineer’s approval produced in AutoCAD software in 584.5 mm x 413.5 mm (A-2 size) standard drawing paper, and operating and maintenance manual of the equipment and plant incorporated in the works, if any, in original by the date stated in the particular conditions of contract (PCC). If the contractor does not supply the as-built drawings and operating & maintenance manuals by the date stated in the particular conditions of contract (PCC), or they do','per tender',2025,5,'2026-06-08 07:31:27',NULL,NULL,1,NULL,'1',NULL,29040.89,29040.89,29040.89,29040.89);
