INSERT INTO "rate_audit_log" VALUES(18,1,'admin','admin','CREATE','parent','2.02.2',NULL,'{"code": "2.02.2", "description": "EFW(AE): Earth filling work with specified soil in any type of embankment, where earth shall be arranged by the contractor''s own cost including royalty, cutting, carrying, filling and compacting to 85%/95%/98% of Maximum Dry Density (MDD) at Optimum Moisture Content (OMC), with reference to laboratory density test AASHTO standard hammer by throwing earth in layers not more than 150mm in each layer in proper alignment, grade, camber and side slope in all types of soil except rocky, gravelly and slushy including benching not more than 300mm in vertical and 600mm in horizontal steps along the sides while widening any embankment with clod breaking to maximum size of 100mm, benching the side slopes, removing roots and stumps of trees of girth upto 200mm and other foreign particles stripping/ ploughing the base of embankment and borrow pit area, dug bailing, clearing jungles, bail out of water, rough dressing including 150mm cambering at the centre of crest  with  all  leads  and  lifts complete (compaction  will  be done by the contractor with approved equipment including all ancillary charges for compaction and testing) as per direction of Engineer in charge. Payment will be made on compacted volume."}',NULL,'2026-06-06 10:31:18');
