PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE activity_logs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    company_id INTEGER NOT NULL REFERENCES companies(id),
    actor_user_id INTEGER NOT NULL REFERENCES users(id),
    action_type TEXT NOT NULL,  -- 'registration', 'update', 'login', 'pdf_export', etc.
    target_type TEXT NOT NULL,  -- 'user', 'tender', 'analysis', etc.
    target_id TEXT NOT NULL,    -- ID of the affected resource
    details TEXT,               -- JSON string with additional context
    ip_address TEXT,
    user_agent TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE bid_revisions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        revision_number INTEGER,
        bid_amount REAL,
        revised_by INTEGER,
        reason TEXT,
        revised_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id),
        FOREIGN KEY (revised_by) REFERENCES users (id)
    );
CREATE TABLE bid_submissions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                boq_history_id INTEGER,
                tender_id TEXT,
                company_id INTEGER,
                submitted_bid_amount REAL,
                bid_document_path TEXT,
                submission_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                submitted_by TEXT,
                status TEXT DEFAULT 'draft',
                notes TEXT,
                FOREIGN KEY (boq_history_id) REFERENCES boq_generation_history(id) ON DELETE CASCADE,
                FOREIGN KEY (tender_id) REFERENCES tenders_boq_meta(tender_id) ON DELETE SET NULL
            );
CREATE TABLE boq_activity_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            boq_id INTEGER,
            action TEXT,
            details TEXT,
            user_id INTEGER,
            username TEXT,
            user_role TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (boq_id) REFERENCES boq_generation_history(id) ON DELETE CASCADE
        );
CREATE TABLE boq_approval_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            boq_id INTEGER NOT NULL,
            action TEXT NOT NULL,
            comment TEXT,
            user_id INTEGER,
            username TEXT,
            user_role TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (boq_id) REFERENCES boq_generation_history(id) ON DELETE CASCADE
        );
CREATE TABLE boq_generation_history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER,
                company_id INTEGER,
                tender_id TEXT,
                tender_title TEXT,
                procuring_entity TEXT,
                file_name TEXT,
                item_count INTEGER,
                total_estimated_cost REAL,
                selected_zone TEXT,
                rate_source TEXT,
                edition_year INTEGER,
                generated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                status TEXT DEFAULT 'completed',
                notes TEXT, created_at TIMESTAMP, updated_at TIMESTAMP, is_locked BOOLEAN DEFAULT 0, locked_at TIMESTAMP, locked_by INTEGER,
                FOREIGN KEY (tender_id) REFERENCES tenders_boq_meta(tender_id) ON DELETE SET NULL
            );
CREATE TABLE boq_items (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            boq_id INTEGER NOT NULL,
            item_code TEXT NOT NULL,
            description TEXT,
            unit TEXT,
            quantity REAL DEFAULT 0,
            unit_rate REAL DEFAULT 0,
            total REAL DEFAULT 0,
            is_custom BOOLEAN DEFAULT 0,
            notes TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (boq_id) REFERENCES boq_generation_history(id) ON DELETE CASCADE
        );
CREATE TABLE certificate (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                company_id INTEGER NOT NULL,
                certificate_name TEXT NOT NULL,
                certificate_number TEXT,
                issuing_body TEXT NOT NULL,
                issue_date DATE,
                expiry_date DATE,
                certificate_type TEXT,
                grade TEXT,
                scope TEXT,
                document_path TEXT,
                verification_status TEXT DEFAULT 'pending',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(company_id, certificate_number),
                FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE
            );
CREATE TABLE companies (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_name TEXT UNIQUE NOT NULL,
            registration_number TEXT,
            vat_number TEXT,
            address TEXT,
            city TEXT,
            division TEXT,
            phone TEXT,
            email TEXT,
            website TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            is_active BOOLEAN DEFAULT 1
        , district TEXT, status TEXT DEFAULT 'active', is_individual BOOLEAN DEFAULT 0, upazila TEXT, post_code TEXT, tin_number TEXT, bin_number TEXT, rjsc_number TEXT, updated_at TIMESTAMP);
CREATE TABLE company_documents (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER NOT NULL,
            document_name TEXT NOT NULL,
            document_type TEXT NOT NULL,
            file_path TEXT NOT NULL,
            file_name TEXT,
            description TEXT,
            document_date DATE,
            expiry_date DATE,
            uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            uploaded_by INTEGER
        );
CREATE TABLE company_financials (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER NOT NULL,
            fiscal_year TEXT NOT NULL,
            annual_turnover REAL,
            construction_turnover REAL,
            net_worth REAL,
            working_capital REAL,
            liquid_assets REAL,
            credit_limit REAL,
            bank_guarantee_limit REAL,
            is_audited BOOLEAN DEFAULT 0,
            audit_firm TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
CREATE TABLE company_licenses (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER NOT NULL,
            license_type TEXT NOT NULL,
            license_number TEXT NOT NULL,
            issuing_authority TEXT,
            issue_date DATE,
            expiry_date DATE,
            license_file_path TEXT,
            status TEXT DEFAULT 'active',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
CREATE TABLE company_nppi (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        company_id INTEGER,
        procurement_type TEXT,
        nppi_factor REAL,
        data_points INTEGER,
        calculation_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (company_id) REFERENCES companies (id),
        UNIQUE(company_id, procurement_type, calculation_date)
    );
CREATE TABLE company_personnel (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER NOT NULL,
            name TEXT NOT NULL,
            designation TEXT NOT NULL,
            nid_number TEXT,
            phone TEXT,
            email TEXT,
            educational_qualification TEXT,
            experience_years INTEGER,
            is_key_personnel BOOLEAN DEFAULT 0,
            cv_file_path TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
CREATE TABLE company_profile (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER NOT NULL UNIQUE,
            legal_name TEXT,
            trade_name TEXT,
            registration_number TEXT,
            registered_address TEXT,
            phone_primary TEXT,
            email_primary TEXT,
            division TEXT,
            district TEXT,
            website TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_by INTEGER
        );
CREATE TABLE company_tenders (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        company_id INTEGER,
        tender_id TEXT,
        tender_title TEXT,
        procuring_entity TEXT,
        division TEXT,
        district TEXT,
        thana TEXT,
        country TEXT DEFAULT 'Bangladesh',
        procurement_type TEXT,
        official_estimate REAL,
        submission_deadline TIMESTAMP,
        tender_security REAL,
        document_fee REAL,
        evaluation_type TEXT,
        mode_of_payment TEXT,
        eligibility_criteria TEXT,
        invitation_ref_no TEXT,
        package_no TEXT,
        project_code TEXT,
        project_name TEXT,
        inviting_official_name TEXT,
        inviting_official_designation TEXT,
        inviting_official_phone TEXT,
        inviting_official_email TEXT,
        inviting_official_address TEXT,
        inviting_official_city TEXT,
        inviting_official_thana TEXT,
        inviting_official_district TEXT,
        our_bid_amount REAL,
        bid_submitted_by INTEGER,
        bid_submission_date TIMESTAMP,
        bid_status TEXT DEFAULT 'draft',
        evaluation_status TEXT DEFAULT 'pending',
        winning_bid_amount REAL,
        winning_competitor TEXT,
        our_rank INTEGER,
        total_bidders INTEGER,
        award_date DATE,
        notes TEXT,
        created_by INTEGER,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, is_locked BOOLEAN DEFAULT 0, locked_at TIMESTAMP, locked_by INTEGER, is_copy BOOLEAN DEFAULT 0, original_tender_id INTEGER, is_active BOOLEAN DEFAULT 1, deleted_at TIMESTAMP, deleted_by INTEGER, app_id TEXT, procuring_entity_code TEXT, procurement_nature TEXT, event_type TEXT, budget_type TEXT, source_of_funds TEXT, category TEXT, tender_publication_date TIMESTAMP, document_selling_end_date TIMESTAMP, pre_bid_meeting_start TIMESTAMP, pre_bid_meeting_end TIMESTAMP, bid_opening_date TIMESTAMP, security_submission_deadline TIMESTAMP, security_valid_upto DATE, tender_valid_upto DATE,
        UNIQUE(company_id, tender_id),
        FOREIGN KEY (company_id) REFERENCES companies (id),
        FOREIGN KEY (bid_submitted_by) REFERENCES users (id),
        FOREIGN KEY (created_by) REFERENCES users (id)
    );
