                edition_year INTEGER,
                import_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                imported_by TEXT,
                total_parents INTEGER,
                total_children INTEGER,
                total_rates INTEGER,
                status TEXT DEFAULT 'active',
                notes TEXT,
                FOREIGN KEY (version_id) REFERENCES pwd_versions(id)
            );
CREATE TABLE pwd_parent_items (
                pwd_code TEXT PRIMARY KEY,
                description TEXT,
                chapter_number TEXT,
                has_children BOOLEAN DEFAULT 0,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
CREATE TABLE pwd_parents (
                pwd_code TEXT PRIMARY KEY,
                description TEXT,
                chapter_number TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            , version_id INTEGER REFERENCES pwd_versions(id));
CREATE TABLE pwd_rates (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                pwd_code TEXT NOT NULL,
                zone_name TEXT NOT NULL,
                unit_rate REAL NOT NULL,
                edition_year INTEGER NOT NULL,
                version_id INTEGER,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(pwd_code, zone_name, edition_year),
                FOREIGN KEY (pwd_code) REFERENCES pwd_children(pwd_code) ON DELETE CASCADE
            );
CREATE TABLE pwd_snapshots (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                snapshot_name TEXT,
                version_id INTEGER,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                created_by TEXT,
                description TEXT,
                data_json TEXT,
                is_auto BOOLEAN DEFAULT 0,
                FOREIGN KEY (version_id) REFERENCES pwd_versions(id)
            );
CREATE TABLE pwd_versions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                version_name TEXT NOT NULL,
                edition_year INTEGER NOT NULL,
                effective_from DATE,
                effective_to DATE,
                is_active BOOLEAN DEFAULT 0,
                released_by TEXT,
                release_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                notes TEXT, rollback_status TEXT DEFAULT 'stable', previous_version_id INTEGER,
                UNIQUE(edition_year)
            );
CREATE TABLE rate_audit_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER,
                    username TEXT,
                    role TEXT,
                    action TEXT,
                    entity_type TEXT,
                    entity_id TEXT,
                    old_data TEXT,
                    new_data TEXT,
                    ip_address TEXT,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );
CREATE TABLE rate_change_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                source TEXT NOT NULL,
                version_id INTEGER,
                action TEXT,
                changed_by TEXT,
                changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                details TEXT
            );
CREATE TABLE rate_chapters (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    source VARCHAR(20) NOT NULL,
                    version_id INTEGER NOT NULL,
                    chapter_number VARCHAR(20) NOT NULL,
                    chapter_name TEXT,
                    description TEXT,
                        display_order INTEGER DEFAULT 0,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (version_id) REFERENCES rate_versions(id) ON DELETE CASCADE,
                    UNIQUE(source, version_id, chapter_number)
                );
CREATE TABLE rate_import_history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                source TEXT NOT NULL CHECK(source IN ('PWD', 'LGED')),
                version_id INTEGER,
                version_name TEXT,
                edition_year INTEGER,
                import_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                imported_by TEXT,
                total_parents INTEGER,
                total_children INTEGER,
                total_rates INTEGER,
                status TEXT DEFAULT 'active',
                notes TEXT
            );
CREATE TABLE rate_sections (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    source VARCHAR(20) NOT NULL,
                    version_id INTEGER NOT NULL,
                    chapter_id INTEGER NOT NULL,
                    section_number VARCHAR(20) NOT NULL,
                    section_name TEXT,
                    description TEXT,
                        display_order INTEGER DEFAULT 0,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (version_id) REFERENCES rate_versions(id) ON DELETE CASCADE,
                    FOREIGN KEY (chapter_id) REFERENCES rate_chapters(id) ON DELETE CASCADE,
                    UNIQUE(source, version_id, chapter_id, section_number)
                );
CREATE TABLE rate_snapshots (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                source TEXT NOT NULL CHECK(source IN ('PWD', 'LGED')),
                version_id INTEGER,
                snapshot_name TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                created_by TEXT,
                description TEXT,
                data_json TEXT,
                is_auto BOOLEAN DEFAULT 0
            );
CREATE TABLE "rate_versions" (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            source TEXT NOT NULL,
            version_name TEXT NOT NULL,
            edition_year INTEGER NOT NULL,
            version_number INTEGER DEFAULT 1,
            effective_from DATE,
            effective_to DATE,
            is_active BOOLEAN DEFAULT 0,
            released_by TEXT,
            release_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            notes TEXT,
            total_parents INTEGER DEFAULT 0,
            total_children INTEGER DEFAULT 0,
            total_rates INTEGER DEFAULT 0,
            created_by TEXT,
            has_sections BOOLEAN DEFAULT FALSE,
            chapter_numbers TEXT,
            section_numbers TEXT,
            updated_at TIMESTAMP, created_at TIMESTAMP,
            UNIQUE(source, edition_year, version_number)
        );
CREATE TABLE regional_rates (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                pwd_code TEXT NOT NULL,
                zone_name TEXT NOT NULL,
                unit_rate REAL NOT NULL,
                edition_year INTEGER NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(pwd_code, zone_name, edition_year),
                FOREIGN KEY (pwd_code) REFERENCES pwd_child_items(pwd_code) ON DELETE CASCADE
            );
CREATE TABLE role_permissions (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        role TEXT UNIQUE NOT NULL,
        permissions TEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
CREATE TABLE saved_scenarios (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            scenario_uuid TEXT UNIQUE NOT NULL,
            company_id INTEGER NOT NULL,
            user_id INTEGER NOT NULL,
            tender_id INTEGER,
            scenario_name TEXT NOT NULL,
            description TEXT,
            
            -- Generation parameters
            official_estimate REAL NOT NULL,
            procurement_type TEXT NOT NULL,
            min_price_pct REAL DEFAULT 0.88,
            max_price_pct REAL DEFAULT 1.08,
            competitor_counts TEXT NOT NULL,  -- JSON array
            bidding_pattern TEXT DEFAULT 'realistic',
            ai_strategy TEXT DEFAULT 'weighted_ensemble',
            random_seed INTEGER DEFAULT 42,
            
            -- Results
            recommended_bid REAL NOT NULL,
            bid_ratio REAL NOT NULL,
            confidence_score REAL NOT NULL,
            expected_win_probability REAL,
            
            -- Scenario data (JSON)
            scenarios_data TEXT NOT NULL,  -- Full scenario details
            competitor_stats TEXT,         -- JSON stats
            
            -- Metadata
            is_favorite BOOLEAN DEFAULT 0,
            view_count INTEGER DEFAULT 0,
            share_token TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            
            FOREIGN KEY (company_id) REFERENCES companies(id),
            FOREIGN KEY (user_id) REFERENCES users(id),
            FOREIGN KEY (tender_id) REFERENCES company_tenders(id)
        );
CREATE TABLE scenario_comments (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            scenario_id INTEGER NOT NULL,
            user_id INTEGER NOT NULL,
            comment TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (scenario_id) REFERENCES saved_scenarios(id) ON DELETE CASCADE,
            FOREIGN KEY (user_id) REFERENCES users(id)
        );
CREATE TABLE scenario_shares (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            scenario_id INTEGER NOT NULL,
            shared_by_user_id INTEGER NOT NULL,
            shared_with_company_id INTEGER,
            shared_with_email TEXT,
            permission TEXT DEFAULT 'view',  -- view, edit, full
            share_token TEXT UNIQUE,
            expires_at TIMESTAMP,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (scenario_id) REFERENCES saved_scenarios(id) ON DELETE CASCADE,
            FOREIGN KEY (shared_by_user_id) REFERENCES users(id),
            FOREIGN KEY (shared_with_company_id) REFERENCES companies(id)
        );
CREATE TABLE schema_migrations (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                version TEXT UNIQUE NOT NULL,
                name TEXT NOT NULL,
                applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                success BOOLEAN DEFAULT 1
            );
CREATE TABLE semantic_search_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                company_id INTEGER NOT NULL,
                user_id INTEGER NOT NULL,
                query_text TEXT NOT NULL,
                query_embedding BLOB,
                result_count INTEGER,
                search_type TEXT,
                response_time_ms INTEGER,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (company_id) REFERENCES companies(id),
                FOREIGN KEY (user_id) REFERENCES users(id)
            );
CREATE TABLE subscription_plans (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                plan_name TEXT UNIQUE NOT NULL,
                plan_type TEXT DEFAULT 'company',
                monthly_price REAL DEFAULT 0,
                yearly_price REAL DEFAULT 0,
                max_boq_generations INTEGER DEFAULT 5,
                max_bid_optimizations INTEGER DEFAULT 5,
                max_tender_analyses INTEGER DEFAULT 5,
                max_users INTEGER DEFAULT 1,
                can_export_data BOOLEAN DEFAULT 0,
                can_edit_rates BOOLEAN DEFAULT 0,
                can_delete_rates BOOLEAN DEFAULT 0,
                can_create_versions BOOLEAN DEFAULT 0,
                can_manage_team BOOLEAN DEFAULT 0,
                description TEXT,
                is_active BOOLEAN DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            , extension_auto_fills INTEGER DEFAULT 5);
CREATE TABLE "subscriptions" (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER REFERENCES users(id),      -- For consultant personal plans
    company_id INTEGER REFERENCES companies(id), -- For company/firm plans
    plan TEXT DEFAULT 'free',
    status TEXT DEFAULT 'inactive',
    start_date DATE,
    end_date DATE,
    analyses_used INTEGER DEFAULT 0,
    analyses_limit INTEGER DEFAULT 5,
    payment_method TEXT,
    transaction_id TEXT,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, created_at TIMESTAMP, max_boq_generations INTEGER DEFAULT 5, max_bid_optimizations INTEGER DEFAULT 5, boq_used INTEGER DEFAULT 0, bid_optimizations_used INTEGER DEFAULT 0, can_edit_rates BOOLEAN DEFAULT 0, can_delete_rates BOOLEAN DEFAULT 0, can_create_versions BOOLEAN DEFAULT 0, can_export_data BOOLEAN DEFAULT 0, can_manage_team BOOLEAN DEFAULT 0, last_reset_date DATE,
    -- App rule: Exactly ONE of (user_id, company_id) must be NOT NULL
    CHECK(
        (user_id IS NOT NULL AND company_id IS NULL) OR
        (user_id IS NULL AND company_id IS NOT NULL)
    )
);
CREATE TABLE system_config (
                key TEXT PRIMARY KEY,
                value TEXT,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_by INTEGER
            );
CREATE TABLE tender_analyses (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER,
            company_id INTEGER,
            tender_id TEXT,
            tender_title TEXT,
            procuring_entity TEXT,
            division TEXT,
            construction_type TEXT,
            official_estimate REAL,
            recommended_bid REAL,
            actual_bid REAL,
            success_probability REAL,
            risk_level TEXT,
            competitor_count INTEGER,
            bid_status TEXT,
            analysis_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP, district TEXT, thana TEXT, competitor_bids TEXT, risk_strategy TEXT, confidence_score REAL, expected_profit REAL, expected_value REAL, slt_threshold REAL, nppi_factor REAL, weighted_average REAL, analysis_type TEXT DEFAULT "Basic", final_submitted_bid REAL, is_final_submitted BOOLEAN DEFAULT 0, actual_winning_bid REAL, actual_winner TEXT, our_rank_actual INTEGER, total_bidders_actual INTEGER, bid_accuracy_score REAL, lessons_learned TEXT, post_evaluation_date TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id),
            FOREIGN KEY (company_id) REFERENCES companies (id)
        );
