CREATE TABLE tender_boq_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                tender_id TEXT,
                item_no TEXT,
                group_name TEXT,
                item_code TEXT,
                description TEXT,
                unit TEXT,
                quantity REAL,
                unit_rate REAL,
                last_modified_by TEXT,
                FOREIGN KEY(tender_id) REFERENCES tenders_boq_meta(tender_id) ON DELETE CASCADE
            );
CREATE TABLE tender_documents (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        document_name TEXT,
        document_type TEXT,
        file_path TEXT,
        uploaded_by INTEGER,
        uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id),
        FOREIGN KEY (uploaded_by) REFERENCES users (id)
    );
CREATE TABLE tender_lots (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        lot_no TEXT,
        lot_description TEXT,
        location TEXT,
        security_amount REAL,
        estimated_value REAL,
        start_date DATE,
        completion_date DATE,
        our_bid_amount REAL,
        bid_status TEXT,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id)
    );
CREATE TABLE tender_milestones (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        milestone_name TEXT,
        due_date DATE,
        completed BOOLEAN DEFAULT 0,
        completed_at TIMESTAMP,
        assigned_to INTEGER,
        notes TEXT,
        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id),
        FOREIGN KEY (assigned_to) REFERENCES users (id)
    );
CREATE TABLE tender_notifications (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        notification_type TEXT,
        notification_date TIMESTAMP,
        sent BOOLEAN DEFAULT 0,
        sent_at TIMESTAMP,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id)
    );
CREATE TABLE tender_response_template (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                company_id INTEGER NOT NULL,
                template_name TEXT NOT NULL,
                template_type TEXT,
                description TEXT,
                sections TEXT,
                field_mappings TEXT,
                version INTEGER DEFAULT 1,
                is_active BOOLEAN DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                created_by INTEGER,
                UNIQUE(company_id, template_name),
                FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE
            );
CREATE TABLE tender_team_assignments (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        tender_id INTEGER,
        user_id INTEGER,
        role TEXT,
        assigned_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, is_active BOOLEAN DEFAULT 1,
        FOREIGN KEY (tender_id) REFERENCES company_tenders (id),
        FOREIGN KEY (user_id) REFERENCES users (id)
    );
CREATE TABLE tenders_boq_meta (
                tender_id TEXT PRIMARY KEY,
                ministry_or_agency TEXT,
                selected_zone TEXT,
                workflow_status TEXT CHECK(workflow_status IN ('Draft', 'Pending Approval', 'Approved')) DEFAULT 'Draft',
                official_budget_cap REAL DEFAULT 0.0,
                created_by TEXT,
                approved_by TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );
CREATE TABLE user_roles (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            role_name TEXT UNIQUE,
            permissions TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
CREATE TABLE users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            company_id INTEGER,
            username TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            email TEXT UNIQUE NOT NULL,
            full_name TEXT,
            phone TEXT,
            role TEXT DEFAULT 'user',
            is_active BOOLEAN DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            last_login TIMESTAMP,
            created_by INTEGER, is_approved BOOLEAN DEFAULT 0, approved_by INTEGER, approved_at TIMESTAMP, registration_complete BOOLEAN DEFAULT 0, company_name TEXT, account_type TEXT DEFAULT 'company', auth_provider TEXT DEFAULT 'email', email_verified BOOLEAN DEFAULT 0, email_verified_at TIMESTAMP, verification_token TEXT, reset_token TEXT, reset_token_expires TIMESTAMP, specialization TEXT, years_experience INTEGER, is_company_admin BOOLEAN DEFAULT 0, company_admin_approved_by INTEGER, company_admin_approved_at TIMESTAMP, mobile_verified BOOLEAN DEFAULT 0, mobile_verified_at TIMESTAMP,
            FOREIGN KEY (company_id) REFERENCES companies (id)
        );
CREATE TABLE vector_embeddings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                company_id INTEGER NOT NULL,
                entity_type TEXT NOT NULL,
                entity_id INTEGER NOT NULL,
                field_name TEXT,
                embedding_model TEXT NOT NULL,
                embedding_dimension INTEGER,
                embedding_vector BLOB NOT NULL,
                original_text TEXT,
                content_hash TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(company_id, entity_type, entity_id, field_name, embedding_model),
                FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE
            );
CREATE TABLE version_change_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                version_id INTEGER,
                source TEXT,
                action TEXT,
                changed_by TEXT,
                changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                details TEXT
            );
CREATE TABLE work_program (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                company_id INTEGER NOT NULL,
                program_name TEXT NOT NULL,
                program_type TEXT,
                description TEXT,
                methodology TEXT,
                quality_control_plan TEXT,
                safety_plan TEXT,
                environmental_plan TEXT,
                resource_requirements TEXT,
                timeline TEXT,
                milestones TEXT,
                document_path TEXT,
                is_standard BOOLEAN DEFAULT 0,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(company_id, program_name),
                FOREIGN KEY (company_id) REFERENCES companies(id) ON DELETE CASCADE
            );
